const update = $input.first().json;

// Handle callback_query (button tap)
if (update.callback_query) {
  const cq = update.callback_query;
  return {
    json: {
      is_callback: true,
      has_file: false,
      command: '',
      callback_id: cq.id,
      callback_data: cq.data || '',
      chat_id: cq.message.chat.id,
      message_id: cq.message.message_id,
      username: cq.from.first_name || cq.from.username || 'there'
    }
  };
}

// Handle regular message
const msg = update.message;
const hasFile = msg.document !== undefined || msg.photo !== undefined;
const text = (msg.text || '').trim();
const chatId = msg.chat.id;
const username = msg.from.first_name || msg.from.username || 'there';

let command = '';
let args = '';

if (!hasFile && text.startsWith('/')) {
  const parts = text.split(' ');
  command = parts[0].toLowerCase().replace(/@.*$/, '');
  args = parts.slice(1).join(' ').trim();
}

return {
  json: {
    is_callback: false,
    has_file: hasFile,
    command,
    args,
    text,
    chat_id: chatId,
    username,
    file_id: msg.document?.file_id || (msg.photo ? msg.photo[msg.photo.length - 1].file_id : null),
    filename: msg.document?.file_name || 'invoice.pdf',
    mime_type: msg.document?.mime_type || 'image/jpeg'
  }
};

const data = $input.first().json;
return {
  json: {
    file_id: data.file_id,
    filename: data.filename,
    mime_type: data.mime_type,
    chat_id: data.chat_id,
    username: data.username
  }
};

const fileInfo = $('Extract File Info').first().json;

// Read binary from filesystem (binaryDataMode: filesystem)
const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64Data = binaryBuffer.toString('base64');

return {
  json: {
    file_base64: base64Data,
    mime_type: fileInfo.mime_type,
    filename: fileInfo.filename,
    chat_id: fileInfo.chat_id,
    username: fileInfo.username,
    received_at: new Date().toISOString()
  }
};

const d = $input.first().json;
const isPdf = d.mime_type === 'application/pdf';

const fileContent = isPdf
  ? {
      type: 'file',
      file: {
        filename: d.filename,
        file_data: `data:${d.mime_type};base64,${d.file_base64}`
      }
    }
  : {
      type: 'image_url',
      image_url: { url: `data:${d.mime_type};base64,${d.file_base64}` }
    };

const prompt = [
  'You are a financial document parser for Indonesian stock broker trade confirmations.',
  '',
  'Extract ALL transactions. Return ONLY a raw JSON array — no markdown, no code blocks, no commentary.',
  '',
  'Output format (always an array):',
  '[{"ticker":"BBCA","company_name":"Bank Central Asia","type":"buy","quantity":10,"price":8950,"fee":25000,"total_amount":8950000,"transaction_date":"2024-02-15","broker":"Mandiri Sekuritas","confidence":0.95}]',
  '',
  'Rules:',
  '- ticker: uppercase, no .JK suffix',
  '- company_name: full company name as printed in the document. If not found, use "unknown"',
  '- type: "buy" (pembelian/beli) or "sell" (penjualan/jual)',
  '- quantity: LOTS only. 1 lot = 100 shares (lembar).',
  '  If document has a lot column → use it directly.',
  '  If document shows only shares → divide by 100.',
  '  Example: "308 lot" → 308 | "30.800 lembar" → 308. NEVER return share count.',
  '- price: price per share in IDR',
  '- fee: broker commission in IDR',
  '- total_amount: shares × price in IDR (before fee)',
  '- transaction_date: YYYY-MM-DD',
  '- confidence: 0.0–1.0 (below 0.7 if uncertain)',
  '',
  `Document: ${d.filename}`
].join('\n');

const payload = {
  model: 'google/gemini-2.5-flash-lite',
  temperature: 0,
  max_tokens: 2048,
  messages: [{
    role: 'user',
    content: [{ type: 'text', text: prompt }, fileContent]
  }]
};

if (isPdf) {
  payload.plugins = [{ id: 'file-parser', pdf: { engine: 'mistral-ocr' } }];
}

return {
  json: {
    chat_id: d.chat_id,
    filename: d.filename,
    mime_type: d.mime_type,
    payload
  }
};

const resp = $input.first().json;
const chatId = $('Build Request').first().json.chat_id;
const filename = $('Build Request').first().json.filename;

let raw = '';
try {
  raw = resp.choices[0].message.content.trim();
} catch(e) {
  return [{ json: { error: true, error_message: 'No response from LLM', chat_id: chatId, filename } }];
}

// Strip markdown code blocks if present
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  return [{ json: { error: true, error_message: e.message, raw_response: raw, chat_id: chatId, filename } }];
}

// Normalize to array
const transactions = Array.isArray(parsed) ? parsed : [parsed];

// Return one item per transaction so Format Confirmation receives all
return transactions.map(t => ({
  json: {
    ticker: (t.ticker || '').toUpperCase().replace(/\.JK$/i, ''),
    company_name: t.company_name || 'unknown',
    type: t.type || 'buy',
    quantity: parseInt(t.quantity) || 0,
    price: parseFloat(t.price) || 0,
    fee: parseFloat(t.fee) || 0,
    total_amount: parseFloat(t.total_amount) || 0,
    transaction_date: t.transaction_date || '',
    broker: t.broker || '',
    confidence: parseFloat(t.confidence) || 0,
    chat_id: chatId,
    filename,
    total_in_batch: transactions.length
  }
}));

const items = $input.all();
const chatId = items[0].json.chat_id;
const filename = items[0].json.filename;
const broker = items[0].json.broker || 'Broker';
const date = items[0].json.transaction_date || '';

// Store batch in workflow static data (persists between executions)
const staticData = $getWorkflowStaticData('global');
const batchId = Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
staticData[`batch_${batchId}`] = items.map(i => i.json);

// Build transaction lines
let totalAmount = 0;
let totalFee = 0;
const lines = items.map((item, idx) => {
  const t = item.json;
  const lots = t.quantity;
  const typeEmoji = t.type === 'buy' ? '🟢' : '🔴';
  const amount = t.total_amount || (lots * 100 * t.price);
  totalAmount += amount;
  totalFee += t.fee || 0;
  return `${idx + 1}. ${typeEmoji} *${t.ticker}* (${t.company_name}) ${lots} lots @ Rp ${Number(t.price).toLocaleString('id-ID')} = Rp ${Number(amount).toLocaleString('id-ID')}`;
});

const confirmData = `confirm_batch|${batchId}`;
const cancelData  = `cancel_batch|${batchId}`;

return [{
  json: {
    chat_id: chatId,
    text: `📄 *Trade Confirmation — ${date}*\n🏦 ${broker}\n📁 ${filename}\n\n${lines.join('\n')}\n\n💸 Total: Rp ${Number(totalAmount).toLocaleString('id-ID')}\n💳 Fee: Rp ${Number(totalFee).toLocaleString('id-ID')}\n\n*Save all ${items.length} transactions?*`,
    reply_markup: [
      { text: `✅ Save All (${items.length})`, callback_data: confirmData },
      { text: '❌ Cancel',                     callback_data: cancelData  }
    ]
  }
}];
